17	type QuoteResult = { premium: number };
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  amulet: 60,
21	  sword: 100,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const PROCESSING_FEE = 5;
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	// Rune-block pricing: 3 runes sold together are priced as a 60 G block
37	// instead of 3 × 25 = 75 G. Adjustment is applied to policy base when an
38	// exact block of 3 runes is present.
39	const RUNE_BLOCK_SIZE = 3;
40	const RUNE_BLOCK_PRICE = 60;
41	const RUNE_BLOCK_ADJUSTMENT =
42	  RUNE_BLOCK_PRICE - RUNE_BLOCK_SIZE * BASE_PREMIUM.rune;
43	
44	function sumOver<T>(xs: T[], f: (x: T) => number): number {
45	  return xs.reduce((total, x) => total + f(x), 0);
46	}
47	
48	// MHPCO rounds quote premiums UP (in the office's favor).
49	function roundUpInFavorOfOffice(amount: number): number {
50	  return Math.ceil(amount);
51	}
52	
53	function itemBasePremium(item: QuoteItem): number {
54	  return BASE_PREMIUM[item.type] ?? 0;
55	}
56	
57	function itemSurcharges(item: QuoteItem): number {
58	  const base = itemBasePremium(item);
59	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const highEnchantmentSurcharge =
61	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
62	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
63	      : 0;
64	  return curseSurcharge + highEnchantmentSurcharge;
65	}
66	
67	function priceQuoteStep(
68	  step: QuoteStep,
69	  yearsWithMHPCO: number,
70	  isFollowUp: boolean,
71	): QuoteResult {
72	  const runeCount = step.items.filter((x) => x.type === "rune").length;
73	  const runeBlockAdjustment =
74	    runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_ADJUSTMENT : 0;
75	  const policyBase = sumOver(step.items, itemBasePremium) + runeBlockAdjustment;
76	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
77	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
78	  const loyaltyDiscount =
79	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
80	      ? policyBase * LOYALTY_DISCOUNT_RATE
81	      : 0;
82	  const followUpDiscount = isFollowUp
83	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
84	    : 0;
85	  const premium = roundUpInFavorOfOffice(
86	    policyBase +
87	      itemSurchargeTotal +
88	      firstInsurance -
89	      loyaltyDiscount -
90	      followUpDiscount +
91	      PROCESSING_FEE,
92	  );
93	  return { premium };
94	}
95	
96	export function runScenario(scenario: Scenario): {
97	  results: QuoteResult[];
98	} {
99	  const results = scenario.steps.map((step, index) =>
100	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
101	  );
102	  return { results };
103	}
